import { NextApiRequest, NextApiResponse } from "next";
import { prisma } from "@/lib/prisma"; // adjust the path to your prisma instance

export async function POST(req: NextApiRequest, res: NextApiResponse) {
	const playlistId = parseInt(req.query.id as string);
	console.log("Playlist ID: ", playlistId);

	if (isNaN(playlistId)) {
		return res.status(400).json({ error: "Invalid playlist ID" });
	}

	if (req.method === "POST") {
		const { songId, externalId } = req.body;

		if (!songId && !externalId) {
			return res
				.status(400)
				.json({ error: "songId or externalId is required" });
		}

		try {
			// Find the song either by ID or external ID
			const song = await prisma.song.findUnique({
				where: songId ? { id: songId } : { externalId: externalId },
			});

			if (!song) {
				return res.status(404).json({ error: "Song not found" });
			}

			// Create or connect the song to the playlist via the join table
			await prisma.playlistSong.create({
				data: {
					playlistId,
					songId: song.id,
				},
			});

			return res.status(201).json({ message: "Song added to playlist" });
		} catch (error: any) {
			if (error.code === "P2002") {
				return res.status(409).json({ error: "Song already in playlist" });
			}

			console.error("Error adding song to playlist:", error);
			return res.status(500).json({ error: "Internal server error" });
		}
	}

	res.setHeader("Allow", ["POST"]);
	return res.status(405).end(`Method ${req.method} Not Allowed`);
}
